const baseUrl= 'http://localhost:3030/jsonstore/movies';
const url =
"https://todo-app-7ea63-default-rtdb.europe-west1.firebasedatabase.app/.json";
export const getAll = async()=>{
    const response = await fetch(url);
    const result = await response.json();

return Object.values(result.tasks);
}

export const getOne = async(taskId)=>{

    const urlGetOne = 'https://todo-app-7ea63-default-rtdb.europe-west1.firebasedatabase.app/tasks'
    const response = await fetch(`https://todo-app-7ea63-default-rtdb.europe-west1.firebasedatabase.app/tasks/${taskId}.json`);
